func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state with restricted access.
	// We skip opening all libraries by default to prevent unauthorized OS/IO access
	// from user-provided scripts.
	L := lua.NewState(lua.Options{SkipOpenLibs: true})
